import React, { useState, useEffect } from 'react';
import { GraduationCap, Search, User, LogOut, Menu, X, Clock, Users, Star, Play, Bookmark } from 'lucide-react';

const Course = ({ courses }) => {
  // Auto-convert Dropbox URLs
  const processedCourses = courses.map(course => ({
    ...course,
    videoUrl: course.videoUrl?.includes('dropbox.com') && course.videoUrl?.includes('dl=0') 
      ? course.videoUrl.replace('dl=0', 'raw=1')
      : course.videoUrl
  }));

  const [filteredCourses, setFilteredCourses] = useState(processedCourses);

  // Convert Dropbox URL to direct video link
  const convertDropboxUrl = (url) => {
    if (url.includes('dropbox.com') && url.includes('dl=0')) {
      return url.replace('dl=0', 'raw=1');
    }
    return url;
  };
  const [activeFilter, setActiveFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('rating');
  const [showMobileMenu, setShowMobileMenu] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [username] = useState('Learner');

  useEffect(() => {
    let filtered = courses.filter(course => {
      const matchesFilter = activeFilter === 'all' || course.cat === activeFilter;
      const matchesSearch = course.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           course.instructor.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesFilter && matchesSearch;
    });

    filtered.sort((a, b) => {
      if (sortBy === 'price') return a.price - b.price;
      if (sortBy === 'enrolled') return b.enrolled - a.enrolled;
      return parseFloat(b.rating) - parseFloat(a.rating);
    });

    setFilteredCourses(filtered);
  }, [courses, activeFilter, searchTerm, sortBy]);

  const CourseCard = ({ course }) => (
    <div className="bg-white rounded-lg overflow-hidden shadow-sm border border-gray-200 hover:transform hover:-translate-y-1 hover:shadow-lg transition-all duration-300">
      <div className="relative h-40 sm:h-48 overflow-hidden">
        <img src={course.img} alt={course.title} className="w-full h-full object-cover" />
        {course.progress > 0 && (
          <div className="absolute top-2 sm:top-3 left-2 sm:left-3 bg-green-600 text-white px-2 py-1 rounded text-xs font-medium">
            {course.progress}% Complete
          </div>
        )}
        <div className="absolute top-2 sm:top-3 right-2 sm:right-3 bg-black/70 text-white px-2 py-1 rounded text-xs flex items-center">
          <Star className="w-3 h-3 mr-1 fill-yellow-400 text-yellow-400" />{course.rating}
        </div>
      </div>
      <div className="p-4 sm:p-6">
        <h3 className="text-base sm:text-lg font-semibold text-gray-900 mb-2">{course.title}</h3>
        <p className="text-gray-600 text-sm mb-3">{course.desc}</p>

        <div className="flex items-center justify-between mb-3 text-xs text-gray-500 flex-wrap gap-1">
          <span className="bg-gray-100 text-gray-700 px-2 py-1 rounded">{course.level}</span>
          <span className="flex items-center">
            <Clock className="w-3 h-3 mr-1" />{course.time}
          </span>
          <span className="flex items-center">
            <Users className="w-3 h-3 mr-1" />{course.enrolled.toLocaleString()}
          </span>
        </div>

        {course.progress > 0 && (
          <div className="mb-4">
            <div className="flex justify-between text-xs text-gray-600 mb-1">
              <span>Progress</span>
              <span>{course.progress}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div className="bg-gradient-to-r from-blue-600 to-blue-800 h-2 rounded-full" style={{width: `${course.progress}%`}}></div>
            </div>
          </div>
        )}

        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
          <div>
            <div className="text-sm text-gray-600">{course.instructor}</div>
            <div className="text-lg font-bold text-blue-600">₹{course.price.toLocaleString()}</div>
          </div>
          <button 
            onClick={() => setSelectedCourse(course)}
            className="w-full sm:w-auto bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition"
          >
            Enroll Now
          </button>
        </div>
      </div>
    </div>
  );

  const Modal = ({ course, onClose }) => (
    <div className="fixed inset-0 flex items-center justify-center bg-black/50 z-50 p-4">
      <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="relative">
          <img className="w-full h-48 sm:h-64 object-cover" src={course.img} alt={course.title} />
          <button onClick={onClose} className="absolute top-4 right-4 bg-white/90 text-gray-700 w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition">
            <X className="w-4 h-4" />
          </button>
        </div>
        <div className="p-6 sm:p-8">
          <div className="flex flex-col sm:flex-row justify-between items-start mb-4 gap-2">
            <h2 className="text-xl sm:text-2xl font-bold text-gray-900">{course.title}</h2>
            <span className="text-xl sm:text-2xl font-bold text-blue-600">₹{course.price.toLocaleString()}</span>
          </div>
          <p className="text-gray-600 mb-6">{course.desc}</p>

          {course.videoUrl && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold mb-3">Course Preview</h3>
              {course.videoUrl.includes('youtube.com') || course.videoUrl.includes('youtu.be') ? (
                <iframe 
                  className="w-full h-64 rounded-lg"
                  src={course.videoUrl.replace('watch?v=', 'embed/')}
                  frameBorder="0"
                  allowFullScreen
                />
              ) : (
                <video 
                  className="w-full h-64 rounded-lg"
                  controls
                  src={course.videoUrl}
                >
                  Your browser does not support the video tag.
                </video>
              )}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Instructor</div>
              <div className="font-semibold text-gray-900">{course.instructor}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Duration</div>
              <div className="font-semibold text-gray-900">{course.time}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Level</div>
              <div className="font-semibold text-gray-900">{course.level}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Students</div>
              <div className="font-semibold text-gray-900">{course.enrolled.toLocaleString()}</div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-4">
            <button className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold py-3 px-6 rounded-lg transition">
              <Play className="w-4 h-4 inline mr-2" />Enroll Now
            </button>
            <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-3 rounded-lg transition">
              <Bookmark className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50" style={{fontFamily: 'Inter, sans-serif'}}>
      <nav className="bg-white shadow-sm fixed w-full z-40 border-b border-gray-200 top-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <a href="#" className="text-blue-600 font-bold text-xl sm:text-2xl flex items-center">
              <GraduationCap className="w-6 h-6 sm:w-8 sm:h-8 mr-2" />RiseGen
            </a>

            <button onClick={() => setShowMobileMenu(!showMobileMenu)} className="md:hidden p-2 rounded-lg text-gray-600 hover:bg-gray-100">
              <Menu className="w-6 h-6" />
            </button>

            <div className="hidden md:flex items-center space-x-4">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="Search courses..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-64 bg-gray-100 text-gray-700 placeholder-gray-500 px-4 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white border border-gray-200"
                />
                <Search className="absolute right-3 top-2.5 w-4 h-4 text-gray-400" />
              </div>
              <div className="flex items-center space-x-2 text-gray-700">
                <User className="w-4 h-4" />
                <span className="text-sm font-medium">{username}</span>
              </div>
              <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm transition">
                <LogOut className="w-4 h-4 inline mr-1" />Logout
              </button>
            </div>
          </div>
        </div>
      </nav>

      <section className="pt-32 pb-12 sm:pb-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-3xl sm:text-4xl lg:text-5xl font-bold mb-4 text-gray-900">Learn Without <span className="text-blue-600">Limits</span></h1>
          <p className="text-lg sm:text-xl mb-8 text-gray-600 max-w-2xl mx-auto">Start, switch, or advance your career with {courses.length} courses, Professional Certificates, and degrees from world-class universities and companies.</p>
          <div className="grid grid-cols-3 gap-4 sm:gap-8 max-w-md mx-auto">
            <div className="text-center">
              <div className="text-2xl sm:text-3xl font-bold text-blue-600">{courses.length}</div>
              <div className="text-xs sm:text-sm text-gray-500">Courses</div>
            </div>
            <div className="text-center">
              <div className="text-2xl sm:text-3xl font-bold text-blue-600">50K+</div>
              <div className="text-xs sm:text-sm text-gray-500">Students</div>
            </div>
            <div className="text-center">
              <div className="text-2xl sm:text-3xl font-bold text-blue-600">100%</div>
              <div className="text-xs sm:text-sm text-gray-500">Online</div>
            </div>
          </div>
        </div>
      </section>

      <div className="bg-gray-100 py-4 sm:py-6">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div className="flex flex-wrap gap-2 w-full sm:w-auto">
              {['all', 'development', 'ai', 'design', 'business'].map(filter => (
                <button 
                  key={filter}
                  onClick={() => setActiveFilter(filter)}
                  className={`px-3 sm:px-4 py-2 rounded-lg border border-gray-300 text-sm transition ${
                    activeFilter === filter 
                      ? 'bg-blue-600 text-white' 
                      : 'text-gray-700 bg-white hover:bg-gray-50'
                  }`}
                >
                  {filter === 'all' ? 'All' : filter === 'ai' ? 'Data Science' : filter.charAt(0).toUpperCase() + filter.slice(1)}
                </button>
              ))}
            </div>
            <select 
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
              className="w-full sm:w-auto bg-white border border-gray-300 rounded-lg px-4 py-2 text-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
            >
              <option value="rating">Sort by Rating</option>
              <option value="price">Sort by Price</option>
              <option value="enrolled">Most Popular</option>
            </select>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 sm:py-12">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
          {filteredCourses.map(course => (
            <CourseCard key={course.id} course={course} />
          ))}
        </div>
      </div>

      {selectedCourse && (
        <Modal course={selectedCourse} onClose={() => setSelectedCourse(null)} />
      )}
    </div>
  );
};

export default Course;
